mapper.update:
UPDATE MESSENGER_USER
SET LEFT_DT = CURRENT_TIMESTAMP
WHERE USER_ID = #{userId}
  AND MSGR_ID = #{msgrId}
  AND LEFT_DT IS NULL

UPDATE MESSENGER_USER
SET NOTIFY_YN = #{notifyYn}
WHERE USER_ID = #{userId}
  AND MSGR_ID = #{msgrId}
  AND LEFT_DT IS NULL

mapper.select:
SELECT USER_ID, MSGR_ID, JOIN_DT, LEFT_DT, ROLE_CD, NOTIFY_YN
FROM MESSENGER_USER
WHERE MSGR_ID = #{msgrId}
  AND USER_ID = #{userId}
LIMIT 1
